module RefModule (
    input clk,
    input x,
    input k,
    input reset,
    output reg out);// State Encoding
    parameter OFF = 0, ON = 1;
    reg [1:0] pipeline_reg, next;

    // State Transition Logic
    always @(*) begin
        case (pipeline_reg)
            OFF: next = x ? ON : OFF;
            ON: next = k ? OFF : ON;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) pipeline_reg <= OFF;
        else pipeline_reg <= next;
    end

    // Output Logic
    always @(*) begin
        case (pipeline_reg)
            OFF: out = 0;
            ON: out = 1;
        endcase
    end
endmodule
